const authData = $input.item.json;
const body = authData.body || {};

const businessUrl = body.business_url || '';
const industry = body.industry || '';
const month = body.month || '';
const platforms = body.platforms || [];
const pipelineRunId = body.pipeline_run_id || '';
const callbackUrl = body.callback_url || '';
const userId = authData.user_id || '';

// Build Jina Reader URL
const jinaUrl = 'https://r.jina.ai/' + businessUrl;

return {
  json: {
    jina_url: jinaUrl,
    business_url: businessUrl,
    industry: industry,
    month: month,
    platforms: platforms,
    pipeline_run_id: pipelineRunId,
    callback_url: callbackUrl,
    user_id: userId
  }
};

const jinaOutput = $input.item.json;
const prepData = $('Prepare Jina URL').item.json;

// Extract content from Jina response
let siteContent = '';
try {
  if (jinaOutput.data && jinaOutput.data.content) {
    siteContent = jinaOutput.data.content;
  } else if (jinaOutput.content) {
    siteContent = jinaOutput.content;
  } else if (typeof jinaOutput === 'string') {
    siteContent = jinaOutput;
  } else {
    siteContent = JSON.stringify(jinaOutput);
  }
} catch(e) {
  siteContent = JSON.stringify(jinaOutput);
}

// Truncate to 12000 chars for Claude
const truncated = siteContent.substring(0, 12000);

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: 'You are a product/service extractor. Analyze website content and extract ALL products, services, or offerings. If the site is not e-commerce, treat service packages, consulting tiers, software plans, or menu items as products.',
  messages: [{
    role: 'user',
    content: 'Analyze this website content and extract ALL products, services, or offerings mentioned.\n\nWEBSITE CONTENT:\n' + truncated + '\n\nReturn a JSON array of products. Each product should have:\n- name: string (product/service name)\n- description: string (brief description, max 100 chars)\n- price: string or null (if price is visible)\n- features: string[] (key features, max 5)\n- image_url: string or null (product image URL if found in page)\n- image_urls: string[] (ALL product image URLs found, including variants/angles)\n- product_url: string or null (link to individual product page if found)\n- category: string (product category)\n\nFor product_url, look for links to individual product/service detail pages. For image_urls, include every image URL you can find associated with the product.\n\nIf the site is not e-commerce, treat service packages, consulting tiers, software plans, or menu items as "products."\n\nReturn ONLY a valid JSON array. No markdown, no explanation.'
  }]
});

return {
  json: {
    apiBody: body,
    site_content: siteContent.substring(0, 3000),
    user_id: prepData.user_id,
    business_url: prepData.business_url,
    industry: prepData.industry,
    month: prepData.month,
    platforms: prepData.platforms,
    pipeline_run_id: prepData.pipeline_run_id,
    callback_url: prepData.callback_url
  }
};

const input = $input.item.json;
const prepData = $('Prepare Extract Products').item.json;

// Extract Claude response text
let raw = '';
try {
  raw = input.content[0].text;
} catch(e) {
  raw = '';
}

// Robust JSON parsing
let products = [];
try {
  products = JSON.parse(raw);
} catch(e) {
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try {
    products = JSON.parse(stripped);
  } catch(e2) {
    const match = stripped.match(/\[[\s\S]*\]/);
    if (match) {
      try {
        products = JSON.parse(match[0]);
      } catch(e3) {
        products = [];
      }
    }
  }
}

if (!Array.isArray(products)) {
  products = [];
}

// Map to products table schema (now includes image_urls + product_url)
const mapped = products.map(p => {
  // Build image_urls: merge image_url + image_urls from Claude
  let imageUrls = [];
  if (Array.isArray(p.image_urls)) {
    imageUrls = p.image_urls.filter(u => typeof u === 'string' && u.length > 0);
  }
  if (p.image_url && !imageUrls.includes(p.image_url)) {
    imageUrls.unshift(p.image_url);
  }
  return {
    user_id: prepData.user_id,
    name: (p.name || 'Unknown Product').substring(0, 255),
    description: (p.description || '').substring(0, 500),
    price: p.price || null,
    features: p.features || [],
    image_url: p.image_url || null,
    image_urls: imageUrls,
    product_url: p.product_url || null,
    category: (p.category || 'General').substring(0, 100),
    source_url: prepData.business_url,
    is_active: true
  };
});

return {
  json: {
    products: mapped,
    products_count: mapped.length,
    user_id: prepData.user_id,
    business_url: prepData.business_url,
    industry: prepData.industry,
    month: prepData.month,
    platforms: prepData.platforms,
    pipeline_run_id: prepData.pipeline_run_id,
    callback_url: prepData.callback_url,
    site_content: prepData.site_content
  }
};

const data = $('Parse Products').item.json;
const products = data.products || [];

if (products.length === 0) {
  // Skip save, pass through
  return {
    json: {
      skipped: true,
      products_count: 0,
      user_id: data.user_id,
      business_url: data.business_url,
      industry: data.industry,
      month: data.month,
      platforms: data.platforms,
      pipeline_run_id: data.pipeline_run_id,
      callback_url: data.callback_url,
      site_content: data.site_content,
      products: []
    }
  };
}

return {
  json: {
    skipped: false,
    products_body: JSON.stringify(products),
    products_count: products.length,
    user_id: data.user_id,
    business_url: data.business_url,
    industry: data.industry,
    month: data.month,
    platforms: data.platforms,
    pipeline_run_id: data.pipeline_run_id,
    callback_url: data.callback_url,
    site_content: data.site_content,
    products: products
  }
};

// Filter to products that have a product_url for deep scraping
const data = $('Prepare Save Products').item.json;
const products = (data.products || []).filter(p => p.product_url && p.product_url.length > 0);

if (products.length === 0) {
  return { json: { items: [], done: true, user_id: data.user_id } };
}

// Return each product as a separate item for SplitInBatches
return products.map(p => ({ json: { ...p, _passthrough_user_id: data.user_id } }));

const jinaOutput = $input.item.json;
const batchItem = $('Loop Products').item.json;

let pageContent = '';
try {
  if (jinaOutput.data && jinaOutput.data.content) {
    pageContent = jinaOutput.data.content;
  } else if (jinaOutput.content) {
    pageContent = jinaOutput.content;
  } else {
    pageContent = JSON.stringify(jinaOutput);
  }
} catch(e) {
  pageContent = '';
}

// Truncate for Claude
const truncated = pageContent.substring(0, 8000);

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2048,
  system: 'You extract product image URLs from webpage content. Return ONLY a JSON array of image URL strings.',
  messages: [{
    role: 'user',
    content: 'Extract ALL product image URLs from this page content for the product: ' + (batchItem.name || 'unknown') + '\n\nPAGE CONTENT:\n' + truncated + '\n\nReturn a JSON array of image URL strings. Include product photos, gallery images, variant images, and lifestyle shots. Exclude icons, logos, and UI elements. Return ONLY the JSON array, no markdown or explanation.'
  }]
});

return {
  json: {
    apiBody: body,
    product_name: batchItem.name,
    product_user_id: batchItem._passthrough_user_id || batchItem.user_id,
    existing_image_urls: batchItem.image_urls || []
  }
};

const input = $input.item.json;
const prepData = $('Prepare Image Extraction').item.json;

let raw = '';
try {
  raw = input.content[0].text;
} catch(e) {
  raw = '[]';
}

let newUrls = [];
try {
  newUrls = JSON.parse(raw);
} catch(e) {
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try { newUrls = JSON.parse(stripped); } catch(e2) { newUrls = []; }
}

if (!Array.isArray(newUrls)) newUrls = [];
newUrls = newUrls.filter(u => typeof u === 'string' && u.startsWith('http'));

// Merge with existing, deduplicate
const existing = prepData.existing_image_urls || [];
const merged = [...new Set([...existing, ...newUrls])];

return {
  json: {
    image_urls: merged,
    product_name: prepData.product_name,
    product_user_id: prepData.product_user_id
  }
};

// Merge point after Save Products or skip
// Recover data from Prepare Save Products
const data = $('Prepare Save Products').item.json;

// Build Perplexity Research 1 prompt: Industry landscape + competitor analysis
const prompt = 'Research the ' + data.industry + ' industry. Provide: 1) Key market trends and growth areas, 2) Top 5-10 competitors for a business like ' + data.business_url + ', 3) Industry-specific content strategies that perform well on social media. Include citations.';

const body = JSON.stringify({
  model: 'sonar-pro',
  messages: [
    {
      role: 'system',
      content: 'You are a market research analyst specializing in social media content strategy. Provide detailed, actionable research with citations.'
    },
    {
      role: 'user',
      content: prompt
    }
  ],
  temperature: 0.3,
  max_tokens: 4000
});

return {
  json: {
    perplexity_body_1: body,
    user_id: data.user_id,
    business_url: data.business_url,
    industry: data.industry,
    month: data.month,
    platforms: data.platforms,
    pipeline_run_id: data.pipeline_run_id,
    callback_url: data.callback_url,
    site_content: data.site_content,
    products: data.products,
    products_count: data.products_count
  }
};

const research1 = $input.item.json;
const prepData = $('Prepare Research 1').item.json;

// Extract research 1 content
let research1Content = '';
try {
  research1Content = research1.choices[0].message.content;
} catch(e) {
  research1Content = JSON.stringify(research1);
}

// Build Perplexity Research 2 prompt: Audience pain points + desires
const prompt = 'Research the target audience for ' + prepData.industry + ' businesses like ' + prepData.business_url + '. Provide: 1) Top pain points and frustrations, 2) Desires and aspirations, 3) Common objections to purchasing, 4) Buying triggers, 5) Where this audience spends time online. Include citations.';

const body = JSON.stringify({
  model: 'sonar-pro',
  messages: [
    {
      role: 'system',
      content: 'You are a consumer psychology researcher specializing in audience analysis for marketing. Provide detailed, actionable insights with citations.'
    },
    {
      role: 'user',
      content: prompt
    }
  ],
  temperature: 0.3,
  max_tokens: 4000
});

return {
  json: {
    perplexity_body_2: body,
    research_1: research1Content,
    user_id: prepData.user_id,
    business_url: prepData.business_url,
    industry: prepData.industry,
    month: prepData.month,
    platforms: prepData.platforms,
    pipeline_run_id: prepData.pipeline_run_id,
    callback_url: prepData.callback_url,
    site_content: prepData.site_content,
    products: prepData.products,
    products_count: prepData.products_count
  }
};

const research2 = $input.item.json;
const prepData = $('Prepare Research 2').item.json;

// Extract research 2 content
let research2Content = '';
try {
  research2Content = research2.choices[0].message.content;
} catch(e) {
  research2Content = JSON.stringify(research2);
}

// Build Perplexity Research 3 prompt: Content gaps + opportunities
const prompt = 'Research content marketing opportunities in the ' + prepData.industry + ' space for ' + prepData.business_url + '. Provide: 1) Underserved content topics, 2) High-engagement content formats, 3) 15-20 trending and niche hashtags for LinkedIn, Instagram, X, and YouTube, 4) Content pillars that resonate with the target audience. Include citations.';

const body = JSON.stringify({
  model: 'sonar-pro',
  messages: [
    {
      role: 'system',
      content: 'You are a content marketing strategist specializing in social media trends and content gap analysis. Provide detailed, actionable research with citations.'
    },
    {
      role: 'user',
      content: prompt
    }
  ],
  temperature: 0.3,
  max_tokens: 4000
});

return {
  json: {
    perplexity_body_3: body,
    research_1: prepData.research_1,
    research_2: research2Content,
    user_id: prepData.user_id,
    business_url: prepData.business_url,
    industry: prepData.industry,
    month: prepData.month,
    platforms: prepData.platforms,
    pipeline_run_id: prepData.pipeline_run_id,
    callback_url: prepData.callback_url,
    site_content: prepData.site_content,
    products: prepData.products,
    products_count: prepData.products_count
  }
};

const research3 = $input.item.json;
const prepData = $('Prepare Research 3').item.json;

// Extract research 3 content
let research3Content = '';
try {
  research3Content = research3.choices[0].message.content;
} catch(e) {
  research3Content = JSON.stringify(research3);
}

// Build product summary for Claude
const productsList = (prepData.products || []).map(p => {
  return '- ' + p.name + (p.price ? ' ($' + p.price + ')' : '') + ': ' + (p.description || 'No description');
}).join('\n');

// Build comprehensive Claude ICP synthesis prompt
const prompt = 'You are a world-class marketing strategist. Based on the following research, create a comprehensive Ideal Customer Profile (ICP) for this business.\n\n' +
  'BUSINESS: ' + prepData.business_url + '\n' +
  'INDUSTRY: ' + prepData.industry + '\n\n' +
  'WEBSITE CONTENT SUMMARY:\n' + (prepData.site_content || 'Not available') + '\n\n' +
  'PRODUCTS/SERVICES OFFERED:\n' + (productsList || 'None extracted') + '\n\n' +
  'RESEARCH 1 - INDUSTRY LANDSCAPE & COMPETITORS:\n' + prepData.research_1 + '\n\n' +
  'RESEARCH 2 - AUDIENCE PAIN POINTS & DESIRES:\n' + prepData.research_2 + '\n\n' +
  'RESEARCH 3 - CONTENT GAPS & OPPORTUNITIES:\n' + research3Content + '\n\n' +
  'Synthesize ALL of the above into a professional ICP. Return a JSON object with EXACTLY these keys:\n' +
  JSON.stringify({
    icp_summary: '2-3 paragraph executive summary of the ideal customer',
    demographics: { age_range: '', gender: '', income_level: '', education: '', location: '', job_titles: [] },
    psychographics: { values: [], interests: [], lifestyle: '' },
    pain_points: ['array of specific pain points'],
    desires: ['array of specific desires and aspirations'],
    objections: ['array of common objections to purchasing'],
    buying_triggers: ['array of triggers that prompt purchasing'],
    content_pillars: [{ name: '', description: '', example_topics: [] }],
    content_preferences: { platforms: {}, content_types: [], best_posting_times: {} },
    competitors: [{ name: '', url: '', strengths: [], weaknesses: [] }],
    content_opportunities: ['array of underserved content topics'],
    recommended_hashtags: { linkedin: [], instagram: [], x: [], youtube: [] }
  }, null, 2) + '\n\nFill in ALL fields with real, researched data. Return ONLY valid JSON. No markdown, no explanation.';

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 8192,
  messages: [{ role: 'user', content: prompt }]
});

return {
  json: {
    apiBody: body,
    raw_research: prepData.research_1 + '\n---\n' + prepData.research_2 + '\n---\n' + research3Content,
    user_id: prepData.user_id,
    business_url: prepData.business_url,
    industry: prepData.industry,
    month: prepData.month,
    platforms: prepData.platforms,
    pipeline_run_id: prepData.pipeline_run_id,
    callback_url: prepData.callback_url,
    products: prepData.products,
    products_count: prepData.products_count
  }
};

const input = $input.item.json;
const prepData = $('Prepare Synthesize ICP').item.json;

// Extract Claude response text
let raw = '';
try {
  raw = input.content[0].text;
} catch(e) {
  raw = JSON.stringify(input);
}

// Robust JSON parsing
let icpParsed = {};
try {
  icpParsed = JSON.parse(raw);
} catch(e) {
  // Strip markdown fences
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try {
    icpParsed = JSON.parse(stripped);
  } catch(e2) {
    // Extract first JSON object
    const match = stripped.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        icpParsed = JSON.parse(match[0]);
      } catch(e3) {
        icpParsed = { icp_summary: raw };
      }
    } else {
      icpParsed = { icp_summary: raw };
    }
  }
}

return {
  json: {
    user_id: prepData.user_id,
    business_url: prepData.business_url,
    industry: prepData.industry,
    icp_summary: icpParsed.icp_summary || '',
    demographics: icpParsed.demographics || {},
    psychographics: icpParsed.psychographics || {},
    content_preferences: icpParsed.content_preferences || {},
    competitors: icpParsed.competitors || [],
    content_opportunities: icpParsed.content_opportunities || [],
    recommended_hashtags: icpParsed.recommended_hashtags || {},
    raw_research: prepData.raw_research,
    content_pillars: icpParsed.content_pillars || [],
    pain_points: icpParsed.pain_points || [],
    desires: icpParsed.desires || [],
    objections: icpParsed.objections || [],
    buying_triggers: icpParsed.buying_triggers || [],
    pipeline_run_id: prepData.pipeline_run_id,
    callback_url: prepData.callback_url,
    products_count: prepData.products_count
  }
};

const saveResult = $input.item.json;
const icpData = $('Parse ICP').item.json;

// Extract ICP ID from save result
let icpId = '';
try {
  const row = Array.isArray(saveResult) ? saveResult[0] : saveResult;
  icpId = row.id || '';
} catch(e) {
  icpId = '';
}

return {
  json: {
    icp_id: icpId,
    products_count: icpData.products_count,
    pipeline_run_id: icpData.pipeline_run_id,
    callback_url: icpData.callback_url
  }
};

// Error handler: catches failures and calls callback with error status
const errorData = $input.item.json;

// Try to recover pipeline_run_id and callback_url from earlier nodes
let pipelineRunId = '';
let callbackUrl = '';
try {
  const prepJina = $('Prepare Jina URL').item.json;
  pipelineRunId = prepJina.pipeline_run_id || '';
  callbackUrl = prepJina.callback_url || '';
} catch(e) {
  // Can't recover, will skip callback
}

return {
  json: {
    pipeline_run_id: pipelineRunId,
    callback_url: callbackUrl,
    error_message: 'ICP Analyzer failed: ' + (errorData.message || errorData.error || 'Unknown error')
  }
};
